var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"여긴…? 내가 있던 곳으로 다시 돌아온 건가?","JPN":"ここは……？　我がいた場所へ戻ったのか？","ENG":"This place is...? Have I returned to where I was?","TWN":"這裡是……？又回到了原本的地方？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…그렇군.","JPN":"……そうか。","ENG":"…Right.","TWN":"……原來如此。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"난 타기리온을 토벌하기 위한 원정에서 괴물과 만나 싸우고 있었지.","JPN":"我はタギリオンを討伐するための遠征で、化け物と出会い戦っていたのか。","ENG":"I was on my way to kill Thagirion, and encountered a monster.","TWN":"我當時在討伐塔基里翁的路上與一個怪物戰鬥。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"가로막는 위협을 제거했다면… 다시 나아가면 될 일이다.","JPN":"阻む脅威を排除したのならば……再び進むまでのこと。","ENG":"With the threat removed... all that is left is to march forward.","TWN":"阻礙你的威脅一旦消失了……你就可以繼續前進。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"마왕은 세계를 파멸로 이끌고, 그 마왕을 쓰러트린 대적자는 또다른 마왕으로 태어난다.","JPN":"魔王は世界を破滅へと導き、その魔王を倒した敵対者はまた違う魔王として生まれ変わる。","ENG":"The Demon Lord causes the end of worlds, and the Antagonist who defeats the Demon Lord is reborn as the new Demon Lord.","TWN":"魔王會將世界引向毀滅，而打敗她的對敵者則會重生為另一個魔王。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"종말을 목도한 세계는 그 끝없는 악순환의 굴레에 갇혀 무너지고 마는 것이지.","JPN":"終末を目の当たりにした世界はその終わりなき悪循環の輪に閉じ込められ、崩壊してしまうのだ。","ENG":"A world that has witnessed its end inevitably collapses after falling into a vicious cycle.","TWN":"目睹末日的世界會陷入永無止境的惡性循環。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"네 곁을 지키던 종자. 그 아이가 바로 대적자다.","JPN":"そなたのそばで見守っていた従者。その子が敵対者である。","ENG":"The myrmidon by your side. That child is the Antagonist.","TWN":"跟在你身邊的那個孩子才是對敵者。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"악이 날 시험하는구나.","JPN":"悪が我を試そうとしているな。","ENG":"Evil is tempting me.","TWN":"邪惡在考驗我。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"이교도의 간사한 예언만큼이나, 악의에 찬 거짓이 틀림없으니.","JPN":"異教徒の邪悪な予言ほど、悪意に満ちた嘘に違いない。","ENG":"Like the prophecies of the pagans, this too is a lie full of malice.","TWN":"宛如異教徒的預言一般充滿惡意的謊言。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"진실을 내 두 눈으로 직접 확인하겠다.","JPN":"真実を我の目で直接確かめようではないか。","ENG":"I must see the truth for myself.","TWN":"我會用自己的雙眼看清真相。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…또 혼자 깨어 있었던 거냐?","JPN":"……また一人で起きていたのか？","ENG":"...What are you doing up alone again?","TWN":"……又獨自醒來了嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"잠을 충분히 자두라 일러 두었거늘.","JPN":"しっかり休んでおくように言ったであろう。","ENG":"I told you to get enough rest.","TWN":"我告訴過你要多睡覺。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"언제 또 바람이 불어서 모닥불이 꺼질지 모르잖아요.","JPN":"いつまた風が吹いて焚火が消えるかわからないじゃないですか。","ENG":"But we don't know when a gust of wind will blow out the campfire.","TWN":"要是風吹滅了營火可怎麼辦？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"잠은 언제든 잘 수 있지만, 추위 때문에 둘 다 감기라도 걸리면 큰일이니까요.","JPN":"寝ることはいつでもできるけど、寒さで二人とも風邪をひいたら大変ですからね。","ENG":"We can sleep at any time, but we'll be in trouble if both of us catch a cold.","TWN":"我們隨時都可以睡覺，但要是因為寒冷而感冒可就是不好了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"인형을 만들고 있었던 건가?","JPN":"人形を作っていたのか？","ENG":"Were you making a doll?","TWN":"你在製作玩偶嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"네, 저희가 지나온 그 마을 폐가에서 재료를 좀 빌려왔어요.","JPN":"はい、私たちが通り過ぎた村の廃屋から材料を少し借りてきました。","ENG":"Yes. I borrowed some material from the ruined village we passed by.","TWN":"是的，我從我們經過的村子裡的一個廢棄房子裡借了一些材料。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"다음 번에 마을을 들르게 되면 그 아이 방에 예쁜 꽃머리띠를 엮어서 놓아두려고요.","JPN":"またその村に寄ることがあれば、その子の部屋に綺麗な花の髪飾りを作って置いておこうと思うんです。","ENG":"The next time we visit that village, I want to make a pretty flower headband and place it in the child's room.","TWN":"等下次路過村子，我要為她編織一條漂亮的花頭巾放在她的房間裡。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"이건… 숙녀와 어린 아이의 인형이구나.","JPN":"これは……大人と子どもの人形だな。","ENG":"These are... dolls of a woman and a girl.","TWN":"這是……淑女和孩子的玩偶。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"헤헤, 행복한 인형 가족이에요.","JPN":"へへ、幸せな人形の家族です。","ENG":"Heh heh, it's a happy doll family.","TWN":"嘿嘿，幸福的玩偶一家人。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그렇다면 이 작은 꼬마가 너인가?","JPN":"ならばこの小さい子どもがそなたなのか？","ENG":"Then, is the little one you?","TWN":"那麼這個小傢伙是你嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"네.","JPN":"はい。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"언니가 화낼 것 같아서 말 못했지만…","JPN":"お姉さんが怒ると思って言えなかったのですが……","ENG":"I never said it because I was worried my sister would get angry...","TWN":"我怕姊姊生氣沒說出來……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"저는 제 어린 시절이 더 행복했어요.","JPN":"私は子どもの頃の方がもっと幸せでした。","ENG":"But I was happier when I was little.","TWN":"其實我覺得童年時期更快樂。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"제 몸에 이상한 상처가 생기는 나쁜 병에 걸린 뒤부터, 언니가 너무 바빠져서 함께 지낼 시간이 별로 없었거든요.","JPN":"私の体に変な傷ができて悪い病気にかかってから、お姉さんが忙しくなって一緒にすごす時間があまり無くなったのです。","ENG":"After I caught a disease that caused a weird wound on my body, my sister became too busy to spend time with me.","TWN":"自從我生了一場大病，身上留下了奇怪的疤痕後，姊姊就變得很忙，我們很少有時間在一起。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"너의 상처는 병이 아니다, 아우드라.","JPN":"そなたの傷は病気ではないのだ、アウドラよ。","ENG":"Your wound is not a disease, Audra.","TWN":"你的傷口不是病，奧德拉。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"성흔은 축복받은 자들에게만 주어지는 것이니.","JPN":"聖痕は祝福された者たちに与えらえるものだからな。","ENG":"The Stigmata is a gift to those who are blessed.","TWN":"是只有受到祝福的人才會獲得的聖痕。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"에이, 절 위해서 거짓말은 안 하셔도 괜찮아요.","JPN":"そんな、私のために嘘なんかつかなくてもいいんですよ。","ENG":"C'mon, you don't have to lie for my sake.","TWN":"唉，不用為了安慰我撒謊。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"저는 이 상처 때문에 정말로 불행해진 걸요.","JPN":"私はこの傷のせいで本当に不幸になったんです。","ENG":"This wound is the reason why I became miserable.","TWN":"因為這個傷口，我變得非常不幸。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"이 상처에 걸린 저주만 아니었어도… 언니가 실종되진 않았을 거라고 마을 어른들이 그랬어요.","JPN":"この傷にかかっている呪いさえ無ければ……お姉さんがいなくなることも無かったって、村の大人たちが言っていました。","ENG":"The village people would say that if it weren't for this wound and its curse... my sister wouldn't have gone missing.","TWN":"村裡的老人家說，如果不是我傷疤上的詛咒……我姊姊就不會失蹤。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그자들의 말은 틀림없는 거짓이다!","JPN":"その者たちの話は紛れもなく嘘だ！","ENG":"What they told you is a complete lie!","TWN":"他們是在撒謊！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"너 같은 아이는 그런 불행한 삶에 어울리지 않아!","JPN":"そなたのような子どもにそんな不幸な人生は相応しくない！","ENG":"A child like you should not be miserable!","TWN":"那種不幸的生活不適合你這種孩子！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"너에게 성흔이 없었다면, 나 혼자만의 힘으로는 마왕도 토벌할 수 없었을 거다!","JPN":"そなたに聖痕が無かったら、我一人の力では魔王を討伐できなかったからな！","ENG":"If you did not have the Stigmata, I alone would not have been able to defeat the Demon Lord!","TWN":"要不是你的聖痕，我一個人根本就沒辦法擊敗魔王！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"어…….","JPN":"えっ……？","ENG":"Uh...","TWN":"嗯……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"에클레시아 님이 그렇게 무섭게 소리지르시는 건 처음 봤어요.","JPN":"エクレシア様がこんなに恐ろしく怒鳴るのを初めて見ました。","ENG":"I never saw you shout so scarily before, Miss Ecclesia.","TWN":"我從來沒見過艾可露西亞說話這麼大聲，有點嚇人。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그건…","JPN":"それは……","ENG":"I...","TWN":"這……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"미안하구나.","JPN":"すまない。","ENG":"I apologize.","TWN":"對不起。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"헤헤, 그만큼 제가 엄청 필요했다고 말씀하신 거죠?","JPN":"へへ、それくらい私が必要だと言ってくださるんですね？","ENG":"Heh heh, but that just means that I'm important to you, right?","TWN":"嘿嘿，說明你非常需要我，對嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"전 그것만으로도 정말 기뻐요.","JPN":"私はそれだけでも嬉しいです。","ENG":"I'm happy just knowing that.","TWN":"光是這一點我就很高興。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"에클레시아 님 말씀을 들으니, 이 상처가 축복이 맞을지도 모르겠다는 생각이 드네요.","JPN":"エクレシア様の話を聞くと、この傷が祝福だと思えるようになります。","ENG":"After hearing what you said, maybe this wound is a blessing.","TWN":"聽艾可露西亞這麼說，我覺得或許這個傷口真的是一種祝福也說不定。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"내가 증명하겠다.","JPN":"我が証明してみせよう。","ENG":"I will prove it to you.","TWN":"我會證明的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"네가 가진 성흔이 저주가 아닌 축복이란 걸, 내가 반드시 증명하마.","JPN":"そなたの聖痕が呪いではなく祝福であると、我が必ず証明しようではないか。","ENG":"I will show you that your Stigmata is a blessing and not a curse.","TWN":"我一定會證明你的聖痕不是詛咒，而是祝福。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"저… 그럼 하나만 약속해주실 수 있나요?","JPN":"あの……でしたら、一つだけ約束してくれますか？","ENG":"Then... could you promise me something?","TWN":"那麼你……能答應我一件事嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"언니를 찾고 나면, 이 상처가 소중한 축복이라고 말해주세요.","JPN":"お姉さんを見つけたら、この傷が大切な祝福だと言ってください。","ENG":"Once we find my sister, please tell her that this wound is a blessing.","TWN":"等我找到姊姊，請告訴她這道傷疤是一個珍貴的祝福。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"언니는 바보 멍청이라서… 축복받은 아이를 혼자 남겨두고 슬프게 한 나쁜 언니라고…","JPN":"お姉さんはバカだから……祝福された子どもを一人にして悲しませた悪いお姉さんだって……","ENG":"Tell her she's stupid... And that she's a bad sister for leaving a blessed child all alone and sad...","TWN":"告訴姊姊她是一個笨蛋傻瓜……是一個讓受到祝福的孩子獨自傷心的壞姊姊……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"꼭 좀 그렇게 말해주세요. 네?","JPN":"必ずそう言ってください。ね？","ENG":"Could you please tell her that? Please?","TWN":"請你一定要這樣對她說，好嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"맹세하마.","JPN":"誓おう。","ENG":"I promise.","TWN":"我發誓。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"내 모든 믿음을 걸고.","JPN":"我の全ての信仰をかけて。","ENG":"On all my faith.","TWN":"以我所有的信仰發誓。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>오셨네요.</color>","JPN":"<color=#ffd34c>来ましたか。</color>","ENG":"<color=#ffd34c>You're here.</color>","TWN":"<color=#ffd34c>你來了。</color>"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>예하께서 오시지 않으면, 직접 찾아 뵈려 했는데.</color>","JPN":"<color=#ffd34c>猊下が来られなかったら、直接会いに行くところでした。</color>","ENG":"<color=#ffd34c>I was meaning to see you myself if you didn't show up, Your Eminence.</color>","TWN":"<color=#ffd34c>如果主教不來，我準備親自去找您。</color>"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>보세요.</color>","JPN":"<color=#ffd34c>見てください。</color>","ENG":"<color=#ffd34c>Look.</color>","TWN":"<color=#ffd34c>請看一看。</color>"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>저도… 언니도… 가장 행복했던 시절을 떠올리며 열심히 조립했어요.</color>","JPN":"<color=#ffd34c>私も……お姉さんも……一番幸せだった頃を思い浮かべながら組み立てました。</color>","ENG":"<color=#ffd34c>I made this... thinking of the happiest time that me... and my sister had.</color>","TWN":"<color=#ffd34c>我……還有姊姊……回想著最幸福的時光製作的。</color>"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…아우드라?","JPN":"……アウドラ？","ENG":"...Audra?","TWN":"……奧德拉？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"네가… 왜 여기에 있는 거지?","JPN":"そなたが……何故ここにいる？","ENG":"What... are you doing here?","TWN":"你……你為什麼會在這裡？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"아아.","JPN":"ああ。","ENG":"Ahh.","TWN":"唉。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"그 이름으로 불러 주셔서 기뻐요.","JPN":"その名前で呼んでくださって嬉しいです。","ENG":"I'm glad you still call me by that name.","TWN":"謝謝主教以這個名字稱呼我。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"제 예전의 모습을 당신이 알아보지 못할까봐…","JPN":"あなたが私の昔の姿をわからないのではないかと……","ENG":"I was worried you might not recognize...","TWN":"我一直擔心您會認不出……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"걱정했거든요.","JPN":"心配しました。","ENG":"what I used to look like.","TWN":"我過去的樣子。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};